Resource: module.edge.aws_wafv2_web_acl.this
File: \modules\edge\main.tf: 17-52
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-logging-policies/bc-aws-logging-33

		17 | resource "aws_wafv2_web_acl" "this" {
		18 |   provider = aws.us_east_1
		19 |   name     = "${var.project}-webacl"
		20 |   scope    = "CLOUDFRONT"
		21 | 
		22 |   default_action {
		23 |     allow {}
		24 |   }
		25 | 
		26 |   # Rate limiting de reservas: max 3 intentos por IP en 5 minutos.
		27 |   rule {
		28 |     name     = "rate-limit-reservas"
		29 |     priority = 1
		30 | 
		31 |     action {
		32 |       block {}
		33 |     }
		34 |     statement {
		35 |       rate_based_statement {
		36 |         limit              = 300
		37 |         aggregate_key_type = "IP"
		38 |       }
		39 |     }
		40 |     visibility_config {
		41 |       cloudwatch_metrics_enabled = true
		42 |       metric_name                = "rate-limit-reservas"
		43 |       sampled_requests_enabled   = true
		44 |     }
		45 |   }
		46 | 
		47 |   visibility_config {
		48 |     cloudwatch_metrics_enabled = true
		49 |     metric_name                = "${var.project}-webacl"
		50 |     sampled_requests_enabled   = true
		51 |   }
		52 | }
